window.__QUIZ_DATA__=[{"id":"objective>Data Processing>2019>1","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"The modern definition of a computing machine is based on a concept known as","images":[],"options":{"A":"circuit switching.","B":"digital circuit.","C":"packet switching.","D":"stored program."},"answer":"D","explanation":"The modern definition of a computing machine is based on a concept known as 'stored program'. This concept, also known as the von Neumann architecture, is a design model for a stored-program digital computer that uses a processing unit and a single separate storage structure to hold both instructions and data.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>2","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"Arrange the following ICT tools in the order of invention from the earliest to the latest:  cell phone, Internet, satellite and radio.","images":[],"options":{"A":"Cell phone, satellite, radio, Internet","B":"Internet, satellite, cell phone, radio","C":"Radio, satellite, Internet, cell phone","D":"Radio, cell phone, satellite, Internet"},"answer":"D","explanation":"Radio, cell phone, satellite and Internet. This is the arrangement of ICT tools in the order of invention from the earliest to the latest.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>3","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"The process of gathering facts and statistics from different sources is known as data","images":[],"options":{"A":"analysis","B":"collection","C":"collation","D":"retrieval"},"answer":"B","explanation":"The process of gathering facts and statistics from different sources is known as data collection. Data collection is the process of gathering and measuring information on variables of interest, in an established systematic fashion that enables one to answer stated research questions, test hypotheses, and evaluate outcomes.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>4","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES","question":"A chart is a graphical representation of","images":[],"options":{"A":"data","B":"map","C":"process","D":"transmission"},"answer":"A","explanation":"A chart is a graphical representation of data or information. It is a diagram, picture or graph which is intended to make information easier to understand.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>5","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"The use of transistors in circuits was a major advancement in the","images":[],"options":{"A":"first generation computers.","B":"second generation computers.","C":"third generation computers.","D":"fourth generation computers."},"answer":"B","explanation":"Second Generation: Transistors (1956-1963)  The transistor was far superior to the vacuum tube, allowing computers to become smaller, faster, cheaper, more energy-efficient and more reliable than their first-generation predecessors.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>6","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"An ICT-based service that uses telecommunication devices to hold meeting among many participants in two or more locations is known as","images":[],"options":{"A":"broadcasting.","B":"multimedia.","C":"podcasting.","D":"teleconference."},"answer":"D","explanation":"Teleconference is an ICT-based service that users telecommunication devices to hold meeting among many participants in two or more location.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>7","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"Which of these devices does not support wireless communication?","images":[],"options":{"A":"GSM phone","B":"Mouse","C":"Router","D":"Telephone"},"answer":"B","explanation":"A mouse is an input device that is used to control the cursor on a computer screen. It is typically connected to the computer using a cable.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>8","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The following hardware devices are used for output operations except","images":[],"options":{"A":"monitor.","B":"microphone.","C":"plotter.","D":"projector."},"answer":"B","explanation":"Microphone is an input device and not output device. Monitor, Plotter and projector are used for output operations.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>9","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"The manipulation of digitized information by computer or other digital electronic equipment is known as","images":[],"options":{"A":"data collation.","B":"data manipulation.","C":"information manipulation.","D":"information processing."},"answer":"D","explanation":"Information processing is the manipulation of digitalized information by computer or other digital electronic equipment.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>10","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Which of the following statements explains information processing?","images":[],"options":{"A":"Saving documents in a device","B":"Changing information detectable by an observer","C":"Data upload to server","D":"Transfer of information between devices"},"answer":"B","explanation":"Information processing involves the change or manipulation of information in a way that makes it detectable or understandable by an observer. It does not merely involve saving documents, uploading data to a server, or transferring information between devices, but rather the transformation of this data into a meaningful format.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>11","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"The information transmission medium from location A to location B in space is called","images":[],"options":{"A":"asynchronous transmission.","B":"guided transmission.","C":"synchronous transmission.","D":"wireless transmission."},"answer":"D","explanation":"The transmission of information from one location to another in space is typically done through wireless transmission. Asynchronous, guided, and synchronous transmissions are types of data transmission methods, but they do not specifically refer to the medium of transmission from one location to another in space.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>12","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"What is the role of the part labelled II in Figure 1?","images":["data:image/png;base64,"],"options":{"A":"Interpreter","B":"Medium","C":"Receiver","D":"Source"},"answer":"B","explanation":"The role of the part labelled II in the diagram above is medium.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>13","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Which of these technologies allows wireless connectivity in a Personal Area Network?","images":[],"options":{"A":"Bandwidth","B":"Bluetooth","C":"Broadband","D":"Satellite"},"answer":"B","explanation":"Bluetooth technology allows wireless connectivity in a Personal Area Network (PAN). A PAN is a network of devices used by an individual for personal or work-related tasks. Bluetooth enables these devices to connect and communicate wirelessly. Bandwidth refers to the data transfer capacity of a network, broadband is a high-speed internet connection, and satellite is a type of wireless transmission technology, but none of these specifically allow wireless connectivity in a PAN.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>14","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The main function of the device in the part labelled II in Figure 2 is","images":["data:image/png;base64,"],"options":{"A":"spending up the rate of data transfer to the part labelled I","B":"providing services to the other devices in the setup","C":"forwarding data packets between computers","D":"controlling the access to the part labelled I"},"answer":"C","explanation":"The main function of the part labelled II in the diagram above is to forward data packets between computers.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>15","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"Use Figure 3 to answer this question      The title of the web page being accessed on the interface in Figure 3 is displayed on the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"The title of the web page being accessed on the interface in the diagram displayed on the part labelled II.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>16","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"Use Figure 3 to answer this question    The shortcut key combination for adding a new tab in Figure 3 is","images":["data:image/png;base64,"],"options":{"A":"Alt + N","B":"Alt + T","C":"Ctrl + N","D":"Ctrl + T"},"answer":"C","explanation":"The shortcut key combination for adding a new tab in the diagram above is Ctrl + N.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>17","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"A program that enables the computer hardware to communicate and function effectively is","images":[],"options":{"A":"translator","B":"liveware","C":"operating system","D":"application software"},"answer":"C","explanation":"Operating system is a program that enables the computer hardware to communicate and function effectively.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>18","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"A Word document can have any of these file extensions except","images":[],"options":{"A":".doc","B":".docx","C":".jpg","D":".rtf"},"answer":"C","explanation":".jpg is a file extension for a graphics file format used in digital photography and web graphics. It is not a file extension for a Word document. Word documents typically have .doc or .docx extensions.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>19","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"Which of the following command shortcuts can be used to display the dialog box in Figure 4 when the application is running?","images":["data:image/png;base64,"],"options":{"A":"Ctrl + O","B":"Ctrl + S","C":"Ctrl + Y","D":"Ctrl + Z"},"answer":"A","explanation":"The command shortcuts that can be used to display the dialog box in the diagram above when the application is running is Ctrl + O.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>20","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"The first step taken in editing a chart in MS Excel is","images":[],"options":{"A":"click and drag the chart object.","B":"click the chart object.","C":"copy the chart object.","D":"drag the chart object."},"answer":"B","explanation":"The first step in editing a chart in MS Excel is to click the chart object. This will activate the chart tools in the ribbon, which allows you to edit the chart.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>21","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"By default, numeric values in a worksheet are","images":[],"options":{"A":"centered.","B":"left-aligned.","C":"right-aligned.","D":"unaligned."},"answer":"C","explanation":"By default, numeric values in a worksheet are right-aligned. This is a standard convention in spreadsheet software like Microsoft Excel to help users easily distinguish numbers from text, which is typically left-aligned.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>22","subject":"Data Processing","year":"2019","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"The diagram in Figure 5 depicts a","images":["data:image/png;base64,"],"options":{"A":"flat file database.","B":"hierarchical database.","C":"network database.","D":"parallel database."},"answer":"C","explanation":"The diagram above in figure 5 depicts a network database.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>23","subject":"Data Processing","year":"2019","type":"Objective","topic":"DATA MANAGEMENT : DATABASE SECURITY","question":"Which of the following sets are available when creating a table in \"Design View\" in Microsoft Access?","images":[],"options":{"A":"DataType, Description and Field Name","B":"Description, Criteria and Field Property.","C":"FieldName, DataType and Field Property","D":"Criteria, FieldName and Description"},"answer":"C","explanation":"When creating a table in Design View in Microsoft Access, the following sets of properties are available:    Field Name: The name of the field.  Data Type: The type of data that the field will store.  Field Properties: Additional properties that control how the field is stored and displayed.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>24","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"The MS Powerpoint feature which can be used to change the appearance of the entire presentation is the","images":[],"options":{"A":"Add slide option.","B":"Design template.","C":"Online view.","D":"Slide Layout option."},"answer":"B","explanation":"The MS powerpoint feature which can be used to change the appearance of the entire presentation is the design template.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>25","subject":"Data Processing","year":"2019","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"One example of web design package is","images":[],"options":{"A":"MS FrontPage","B":"MS Outlook","C":"Peachtree","D":"SPSS"},"answer":"A","explanation":"MS FrontPage is a web design package. It is a WYSIWYG (What You See Is What You Get) editor that allows users to create and edit web pages without knowing HTML. The other options are not web design packages. MS Outlook is an email client, Peachtree is an accounting software, and SPSS is a statistical analysis software.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>26","subject":"Data Processing","year":"2019","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The part labelled II in Figure 6 is used to","images":["data:image/png;base64,"],"options":{"A":"shape objects","B":"select and transform objects","C":"draw lines and curves","D":"create texts"},"answer":"A","explanation":"The part labelled II in the diagram is used to shape object.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>27","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER","question":"In computer maintenance, the dampen material can be used on the following devices except","images":[],"options":{"A":"DVD lens","B":"keyboard","C":"mouse","D":"screen"},"answer":"B","explanation":"In computer maintenance, a dampen material should not be used on a keyboard. This is because the moisture from the dampen material can seep into the keyboard and cause damage to the electronic components. DVD lens, mouse, and screen can be cleaned with a dampen material, but it should be done carefully to avoid damage.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>28","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER","question":"Dust from the system unit casing can be removed using","images":[],"options":{"A":"antistatic wipes.","B":"cotton wool.","C":"static wipes.","D":"wet cloth."},"answer":"A","explanation":"Dust from the system unit casing can be removed using antistatic wipes. These wipes are designed to safely clean electronic equipment without causing static electricity, which can damage electronic components. Cotton wool, static wipes, and wet cloth are not recommended for cleaning the system unit casing as they can generate static electricity or cause moisture damage.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>29","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER ETHICS","question":"Indiscriminate sending of unsolicited e-mails to many e-mail addresses is known as","images":[],"options":{"A":"plagiarism","B":"phishing","C":"pharming","D":"spamming"},"answer":"D","explanation":"Indiscriminate sending of unsolicited e-mails to many e-mail addresses is known as spamming. Spamming is the use of messaging systems to send an unsolicited message (spam) to large numbers of recipients for the purpose of commercial advertising, for the purpose of non-commercial proselytizing, or for any prohibited purpose (especially the fraudulent purpose of phishing).","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>30","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : SAFETY MEASURES","question":"In computing, ergonomics is a term associated with computer","images":[],"options":{"A":"ethics","B":"maintenance","C":"malware detection","D":"safety measure"},"answer":"D","explanation":"The definition of computer ergonomics is the practice of fitting the set up of the computer and the workspace to fit the user and the user's work needs in order to minimize physical stress on the computer user.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>31","subject":"Data Processing","year":"2019","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"Where was Abacus invented?","images":[],"options":{"A":"argentina","B":"australia","C":"china","D":"united states of america"},"answer":"C","explanation":"The first Chinese Abacus was invented around 500 B.C. The Abacus, as we know it today, was used in China around 1300 A.D.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>32","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING","question":"Computer professional bodies in Nigeria include the following except","images":[],"options":{"A":"Internet Service Providers Association of Nigeria.","B":"Nigerian Computer Society.","C":"Nigerian Information Technology Development Agency.","D":"Nigeria Internet Group."},"answer":"A","explanation":"Internet Service Providers Association of Nigeria is not a computer professional bodies in Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>33","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER VIRUS","question":"The malware which appears as a harmless object but attacks its victims at the slightest opportunity is called","images":[],"options":{"A":"worm.","B":"trojan horse.","C":"macro virus.","D":"logic bomb."},"answer":"B","explanation":"The malware which appears as a harmless object but attacks its victims at the slightest opportunity is known as trojan horse.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2019>34","subject":"Data Processing","year":"2019","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER VIRUS","question":"Virus effect can be prevented by","images":[],"options":{"A":"installing and updating antivirus.","B":"installing new operating system.","C":"purchasing new computer.","D":"using external disks on public computer system."},"answer":"A","explanation":"Installing and updating antivirus software is a proven method to prevent virus effects. Antivirus software is specifically designed to detect, prevent, and remove malicious software like viruses. Regular updates are necessary to ensure the software can effectively combat the latest threats.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2019>35","subject":"Data Processing","year":"2019","type":"Objective","topic":"DATA MANAGEMENT : RELATIONAL MODEL","question":"The part of the object in Figure 7 labelled II are called","images":["data:image/png;base64,"],"options":{"A":"attributes.","B":"entitles.","C":"models.","D":"relations."},"answer":"D","explanation":"The part labelled in the diagram above are called Relations.","marks":"1","difficulty":"1"}];